import java.lang.Math;

public static String solve(long n) {
    // Calculate n squared and n cubed
    long nSquared = n * n;
    long nCubed = n * n * n;

    // Convert n squared to hexadecimal
    String hex = Integer.toHexString((int) nSquared).toUpperCase();

    // Convert n cubed to base 36
    String base36 = convertToBase(nCubed, 36).toUpperCase();

    // Concatenate the two strings
    return hex + base36;
}

// Helper method to convert a number to a given base
private static String convertToBase(long number, int base) {
    if (number == 0) {
        return "0";
    }
    StringBuilder result = new StringBuilder();
    while (number > 0) {
        int remainder = (int) (number % base);
        char digit = getDigit(remainder);
        result.insert(0, digit);
        number = number / base;
    }
    return result.toString();
}

// Helper method to get the character representation of a digit in base 36
private static char getDigit(int value) {
    if (value >= 0 && value <= 9) {
        return (char) ('0' + value);
    } else {
        return (char) ('A' + value - 10);
    }
}
